import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.WebService;
import java.math.BigDecimal;

@WebService
public class OrderProcessingService {

    @WebMethod(operationName = "processOrder")
    public String processOrder(@WebParam(name = "orderDetails") OrderDetails orderDetails) {
        // Validate input
        if (orderDetails == null || orderDetails.getItems() == null || orderDetails.getItems().isEmpty()) {
            return "Invalid order details";
        }

        BigDecimal totalPrice = BigDecimal.ZERO;
        for (Item item : orderDetails.getItems()) {
            if (item.getPrice() == null || item.getQuantity() == null) {
                return "Invalid item details";
            }
            totalPrice = totalPrice.add(item.getPrice().multiply(new BigDecimal(item.getQuantity())));
        }

        // Process order
        // Here you would typically integrate with a database or payment gateway

        return "Order processed successfully. Total price: " + totalPrice;
    }
}

